children.text:
@font-face {
    font-family: 'Ahem';
    src: url('file:///Users/henryluo/Projects/lambda-test/layout/data/support/ahem3.ttf') format('truetype');
    font-weight: normal;
    font-style: normal;
}

.container {
  width: 260px;
  font-family: Ahem;
  font-size: 20px;
  line-height: 1.5em;
  border: 1px solid black;
  padding-left: 2px;
}
#test {
    color: green;
}
#test-float-left {
    shape-outside: polygon(0 70px, 50px 120px, 0 120px);
    float: left;
    width: 100px;
    height: 100px;
    margin-top: 20px;
}
#test, #failure-container {
    position: absolute;
    top: 70px;
}
#margin-line {
    position: absolute;
    top: 100px;
    width: 263px;
    border-bottom: 1px solid black;
}
.fail {
    position: absolute;
    height: 20px;
    background-color: red;
    z-index: -1;
}
#bar-1 {
    top: 6px;
    left: 3px;
    width: 240px;
}
#bar-2 {
    top: 36px;
    left: 3px;
    width: 240px;
}
#bar-3 {
    top: 66px;
    left: 23px;
    width: 220px;
}
#bar-4 {
    top: 96px;
    left: 53px;
    width: 200px;
}
#triangle {
    position: absolute;
    top: 90px;
    width: 100px;
    height: 100px;
    background-color: lightblue;
    margin-left: 2px;
    clip-path: polygon(0% 50%, 50% 100%, 0 100%);;

}
